import re
import sys

def extract_info_from_task_002_output(output):
    alternatives = {}

    # Extract information about LibreOffice Calc
    libreoffice_match = re.search(r"LibreOffice Calc.*?\n1\. (.+?)\n", output, re.DOTALL)
    if libreoffice_match:
        info = libreoffice_match.group(1)
        match = re.search(r"Release Notes (.+?) - Latest Release", info)
        if match:
            latest_version = match.group(1)
        else:
            latest_version = 'N/A'

        match = re.search(r"This version may contain a few annoying bugs which will be fixed in the next minor releases to come, although it is stabl", info)
        if match:
            unique_feature = "May contain bugs"
        else:
            unique_feature = 'N/A'

        match = re.search(r"Recommended for technology enthusiasts, early adopters and power users, which contains new features and program enhancements", info)
        if match:
            license = "Free (Open-source)"
        else:
            license = 'N/A'

        alternatives['LibreOffice Calc'] = {
            'Alternative Name': 'LibreOffice Calc',
            'Latest Version': latest_version,
            'License': license,
            'Unique Feature': unique_feature
        }

    # Extract information about alternative names
    alternative_name_matches = re.findall(r"Search results for '(.+?) latest version.*?:", output)

    for name in alternative_name_matches:
        if name not in alternatives:
            alternatives[name] = {
                'Alternative Name': name,
                'Latest Version': 'N/A',
                'License': 'N/A',
                'Unique Feature': 'N/A'
            }

    return alternatives

def create_markdown_table(alternatives):
    table = "| Alternative Name | Latest Version | License | Unique Feature |\n| --- | --- | --- | --- |\n"
    for alternative, info in alternatives.items():
        table += f"| {info['Alternative Name']} | {info['Latest Version']} | {info['License']} | {info['Unique Feature']} |\n"
    return table

def python_exec(dependency_outputs):
    output = dependency_outputs['task_002.output']
    alternatives = extract_info_from_task_002_output(output)
    table = create_markdown_table(alternatives)
    print(table)

